import { TablePreview } from "../../components/tables/TablePreview";
import { tableConfig, type Row } from "./tableConfig";
import { useRowInteractions } from "./useRowInteractions";

interface DataTableProps {
  data: Row[];
}

export default function TeamMembersTable({ data }: DataTableProps) {
  // Typed per-column change handlers — see useRowInteractions.ts.
  // Pass `onCellInteract` to TablePreview to route user edits through your logic.
  const { onCellInteract } = useRowInteractions<Row>();

  return <TablePreview config={tableConfig} data={data} onCellInteract={onCellInteract} />;
}

import { useCallback } from "react";
import type { Row } from "./tableConfig";

/**
 * Per-column user-interaction handlers for this DataTable.
 *
 * One handler per interactive column (dropdown / switch / radio / checkbox /
 * rating). Each receives the full row plus the old and new values so you
 * can react with full context — no extra lookups, no stale closures:
 *
 *   onRoleChange(row, oldValue, newValue)  ← "Role" (dropdown)
 *   onActiveChange(row, oldValue, newValue)  ← "Active" (switch)
 *
 * The hook also exposes a single `onCellInteract(row, key, oldValue, newValue)`
 * dispatcher you can pass straight to <TablePreview onCellInteract={...} />
 * — its signature matches the engine prop exactly and routes each cell
 * change to the matching typed handler above.
 */
export interface UseRowInteractions<TRow extends { id: string }> {
  onRoleChange: (row: TRow, oldValue: string, newValue: string) => Promise<void>;
  onActiveChange: (row: TRow, oldValue: boolean, newValue: boolean) => Promise<void>;
  /**
   * Engine-compatible dispatcher. Signature matches `TablePreviewProps['onCellInteract']`
   * positional argument order: (row, key, oldValue, newValue).
   */
  onCellInteract: (
    row: Record<string, unknown>,
    key: string,
    oldValue: unknown,
    newValue: unknown,
  ) => Promise<void> | void;
}

export function useRowInteractions<TRow extends { id: string } = Row>(): UseRowInteractions<TRow> {
  /**
   * Fires when the user changes the "Role" cell (type: dropdown).
   * Replace the body with your own logic — call an API, dispatch an action,
   * trigger analytics, persist to a store, etc. The full row is passed in
   * so you have id + every other column value without an extra lookup.
   */
  const onRoleChange = useCallback(async (
    row: TRow,
    oldValue: string,
    newValue: string,
  ): Promise<void> => {
    if (oldValue === newValue) return;
    // eslint-disable-next-line no-console
    console.log("[onRoleChange]", { rowId: row.id, oldValue, newValue, row });
    // TODO: e.g. await fetch(`/api/rows/${row.id}`, {
    //   method: "PATCH",
    //   headers: { "Content-Type": "application/json" },
    //   body: JSON.stringify({ "role": newValue }),
    // });
  }, []);

  /**
   * Fires when the user changes the "Active" cell (type: switch).
   * Replace the body with your own logic — call an API, dispatch an action,
   * trigger analytics, persist to a store, etc. The full row is passed in
   * so you have id + every other column value without an extra lookup.
   */
  const onActiveChange = useCallback(async (
    row: TRow,
    oldValue: boolean,
    newValue: boolean,
  ): Promise<void> => {
    if (oldValue === newValue) return;
    // eslint-disable-next-line no-console
    console.log("[onActiveChange]", { rowId: row.id, oldValue, newValue, row });
    // TODO: e.g. await fetch(`/api/rows/${row.id}`, {
    //   method: "PATCH",
    //   headers: { "Content-Type": "application/json" },
    //   body: JSON.stringify({ "active": newValue }),
    // });
  }, []);

  const onCellInteract = useCallback((
    row: Record<string, unknown>,
    key: string,
    oldValue: unknown,
    newValue: unknown,
  ): Promise<void> | void => {
    switch (key) {
      case "role":
        return onRoleChange(row as TRow, oldValue as string, newValue as string);
      case "active":
        return onActiveChange(row as TRow, oldValue as boolean, newValue as boolean);
      default:
        return;
    }
  }, [onRoleChange, onActiveChange]);

  return {
    onCellInteract,
    onRoleChange,
    onActiveChange,
  };
}
